mapper.update:
UPDATE routing_history 
SET is_success = #{success}, 
    response_time_ms = #{responseTimeMs}
WHERE id = #{id}

mapper.select:
SELECT COUNT(CASE WHEN is_success = true THEN 1 END) * 100.0 / COUNT(*)
FROM routing_history
WHERE routed_agent = #{agentName} 
  AND created_at >= #{since}

SELECT AVG(response_time_ms) 
FROM routing_history
WHERE routed_agent = #{agentName} 
  AND is_success = true 
  AND created_at >= #{since}

SELECT * FROM routing_history 
ORDER BY created_at DESC 
LIMIT #{limit}
